import React from 'react';
import { Zap, Paperclip, Clock, AlertCircle } from 'lucide-react';

const NudgeCard = ({ nudge, isSelected, onClick }) => {
  const getPriorityColor = (priority) => {
    switch (priority) {
      case 'high':
        return 'text-red-400';
      case 'normal':
        return 'text-yellow-400';
      case 'low':
        return 'text-green-400';
      default:
        return 'text-gray-400';
    }
  };

  const getPriorityIcon = (priority) => {
    switch (priority) {
      case 'high':
        return <AlertCircle className="w-4 h-4" />;
      case 'normal':
        return <Clock className="w-4 h-4" />;
      case 'low':
        return <Clock className="w-4 h-4" />;
      default:
        return <Clock className="w-4 h-4" />;
    }
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'online':
        return 'bg-green-500';
      case 'away':
        return 'bg-yellow-500';
      case 'offline':
        return 'bg-gray-500';
      default:
        return 'bg-gray-500';
    }
  };

  return (
    <div 
      className={`bg-neutral-700 rounded-lg p-4 cursor-pointer transition-all duration-200 hover:bg-neutral-600 border-2 ${
        isSelected ? 'border-blue-500 bg-neutral-600' : 'border-transparent'
      }`}
      onClick={onClick}
    >
      {/* Header com sender info */}
      <div className="flex items-center gap-3 mb-3">
        <div className="relative">
          <img 
            src={nudge.sender.avatar} 
            alt={nudge.sender.name}
            className="w-10 h-10 rounded-full object-cover"
          />
          <div className={`absolute -bottom-1 -right-1 w-3 h-3 rounded-full border-2 border-neutral-700 ${getStatusColor(nudge.sender.status)}`}></div>
        </div>

        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2">
            <h3 className="text-white font-medium text-sm truncate">{nudge.sender.name}</h3>
            {!nudge.isRead && (
              <div className="w-2 h-2 bg-blue-500 rounded-full flex-shrink-0"></div>
            )}
          </div>
          <p className="text-gray-400 text-xs truncate">{nudge.sender.title}</p>
        </div>

        <div className="flex items-center gap-2 flex-shrink-0">
          <div className={`flex items-center gap-1 ${getPriorityColor(nudge.priority)}`}>
            {getPriorityIcon(nudge.priority)}
          </div>
          <span className="text-gray-400 text-xs">{nudge.timestamp}</span>
        </div>
      </div>

      {/* Nudge icon */}
      <div className="flex items-center gap-2 mb-3">
        <div className="bg-yellow-500/20 p-2 rounded-lg">
          <Zap className="w-4 h-4 text-yellow-500" />
        </div>
        <span className="text-yellow-500 text-sm font-medium">Nudge</span>
      </div>

      {/* Message preview */}
      <div className="mb-3">
        <p className="text-gray-300 text-sm leading-relaxed line-clamp-3">
          {nudge.message}
        </p>
      </div>

      {/* Attachments */}
      {nudge.attachments && nudge.attachments.length > 0 && (
        <div className="flex items-center gap-2 mb-3">
          <Paperclip className="w-4 h-4 text-gray-400" />
          <span className="text-gray-400 text-xs">
            {nudge.attachments.length} attachment{nudge.attachments.length > 1 ? 's' : ''}
          </span>
        </div>
      )}

      {/* Status indicator */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <div className={`w-2 h-2 rounded-full ${nudge.isRead ? 'bg-gray-500' : 'bg-blue-500'}`}></div>
          <span className="text-gray-400 text-xs">
            {nudge.isRead ? 'Read' : 'Unread'}
          </span>
        </div>

        <div className={`px-2 py-1 rounded text-xs font-medium ${
          nudge.priority === 'high' 
            ? 'bg-red-500/20 text-red-400' 
            : nudge.priority === 'normal'
            ? 'bg-yellow-500/20 text-yellow-400'
            : 'bg-green-500/20 text-green-400'
        }`}>
          {nudge.priority.charAt(0).toUpperCase() + nudge.priority.slice(1)}
        </div>
      </div>
    </div>
  );
};

export default NudgeCard;
